#pragma once

#include <array>
#include <functional>
#include <tuple>

#include <ruckig/error.hpp>
#include <ruckig/profile.hpp>


namespace ruckig {

template<size_t, template<class, size_t> class> class TargetCalculator;


//! The trajectory generated by the Ruckig algorithm - (RTOS Stripped version, Single Segment)
template<size_t DOFs, template<class, size_t> class CustomVector = StandardVector>
class Trajectory {
    template<class T> using Vector = CustomVector<T, DOFs>;

    friend class TargetCalculator<DOFs, CustomVector>;

    std::array<Vector<Profile>, 1> profiles;
    double duration {0.0};
    std::array<double, 1> cumulative_times;

    Vector<double> independent_min_durations;

public:
    size_t degrees_of_freedom;

    template<size_t D = DOFs, typename std::enable_if<(D >= 1), int>::type = 0>
    Trajectory(): degrees_of_freedom(DOFs) {
        cumulative_times[0] = 0.0;
    }

    template<size_t D = DOFs, typename std::enable_if<(D == 0), int>::type = 0>
    Trajectory(size_t dofs): degrees_of_freedom(dofs) {
        // In RTOS mode with fixed DOFs, these are usually pre-allocated
        cumulative_times[0] = 0.0;
    }

    //! Get the kinematic state, the jerk, and the section at a given time
    void at_time(double time, Vector<double>& new_position, Vector<double>& new_velocity, Vector<double>& new_acceleration, Vector<double>& new_jerk, size_t& new_section) const {
        new_section = 0;
        
        for (size_t dof = 0; dof < degrees_of_freedom; ++dof) {
            const Profile& p = profiles[0][dof];
            double t = time;

            if (time >= duration) {
                // Constant velocity/acceleration at end
                double t_diff = time - p.t_sum.back() - p.brake.duration;
                std::tie(new_position[dof], new_velocity[dof], new_acceleration[dof]) = integrate(t_diff, p.p.back(), p.v.back(), p.a.back(), 0.0);
                new_jerk[dof] = 0.0;
                continue;
            }

            // Handle brake pre-trajectory
            if (p.brake.duration > 0) {
                if (t < p.brake.duration) {
                    const size_t idx = (t < p.brake.t[0]) ? 0 : 1;
                    double t_sub = (idx == 0) ? t : t - p.brake.t[0];
                    std::tie(new_position[dof], new_velocity[dof], new_acceleration[dof]) = integrate(t_sub, p.brake.p[idx], p.brake.v[idx], p.brake.a[idx], p.brake.j[idx]);
                    new_jerk[dof] = p.brake.j[idx];
                    continue;
                }
                t -= p.brake.duration;
            }

            if (t >= p.t_sum.back()) {
                std::tie(new_position[dof], new_velocity[dof], new_acceleration[dof]) = integrate(t - p.t_sum.back(), p.p.back(), p.v.back(), p.a.back(), 0.0);
                new_jerk[dof] = 0.0;
                continue;
            }

            // Find segment in profile
            size_t idx = 0;
            for (size_t i = 0; i < 7; ++i) {
                if (t < p.t_sum[i]) {
                    idx = i;
                    break;
                }
            }

            double t_sub = (idx == 0) ? t : t - p.t_sum[idx - 1];
            std::tie(new_position[dof], new_velocity[dof], new_acceleration[dof]) = integrate(t_sub, p.p[idx], p.v[idx], p.a[idx], p.j[idx]);
            new_jerk[dof] = p.j[idx];
        }
    }

    void at_time(double time, Vector<double>& new_position, Vector<double>& new_velocity, Vector<double>& new_acceleration) const {
        size_t section;
        Vector<double> jerk;
        at_time(time, new_position, new_velocity, new_acceleration, jerk, section);
    }

    void at_time(double time, Vector<double>& new_position) const {
        Vector<double> velocity, acceleration;
        at_time(time, new_position, velocity, acceleration);
    }

    double get_duration() const {
        return duration;
    }

    Vector<double> get_independent_min_durations() const {
        return independent_min_durations;
    }
};

} // namespace ruckig
